Bind the AudioSource outputAudioMixerGroup property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceOutputAudioMixerGroupBinder _outputAudioMixerGroup;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public AudioMixerGroup _outputAudioMixerGroup;
    }


Bind the AudioSource outputAudioMixerGroup property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        private AudioSourceOutputAudioMixerGroupBinder OutputAudioMixerGroup =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public AudioMixerGroup _outputAudioMixerGroup;
    }

