Switch the AudioSource outputAudioMixerGroup between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private AudioMixerGroup _trueMixer;
        
        private AudioSourceOutputAudioMixerGroupSwitcherBinder IsMixerActive => new(
            _audioSource, _trueMixer, null);
